import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// Icons SVG Minimalist #003366
const Icons = {
  Edit: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>,
  Save: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M5 13l4 4L19 7" /></svg>,
  Delete: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Add: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M12 4v16m8-8H4" /></svg>
};

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updateStaffInfo } = useData();

  // State
  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  const [editMode, setEditMode] = useState(null);
  const [editForm, setEditForm] = useState({});

  // Permissions
  const isChief = user?.role === 'chief';
  const isOp = user?.role === 'op';
  const isReg = user?.role === 'reg';
  const canAccessManager = isChief || isOp || isReg;

  // Functional Roles
  const opFunctionalRoles = ['ST', 'TT', 'CCS', 'CCO', 'CCA'];
  const regFunctionalRoles = ['FFM', 'FFS', 'FFA'];

  if (!canAccessManager) return <div style={{padding: '20px'}}>Bạn không có quyền truy cập trang này.</div>;

  // --- HANDLERS ---
  const handleAdd = (e) => {
    e.preventDefault();
    if (!isChief) return alert("Chỉ Chief Administrator mới được tạo tài khoản!");
    if (!formData.name || !formData.username || !formData.password) return;
    
    addStaff({ 
      ...formData, 
      role: 'staff',
      positions: [],
      baseUBI: 0,
      ubiPercentage: 100,
      status: 'active'
    });
    setFormData({ name: '', username: '', password: '' });
  };

  const handleDelete = (id) => {
    if (!isChief) return alert("Chỉ Chief Administrator mới được xóa tài khoản!");
    if (window.confirm("Bạn có chắc chắn muốn xóa nhân sự này?")) deleteStaff(id);
  };

  const startEdit = (staff) => {
    if (staff.role === 'chief' && !isChief && user.id !== staff.id) {
        return alert("Bạn không có quyền chỉnh sửa thông tin của Chief Admin.");
    }
    setEditMode(staff.id);
    setEditForm({
      name: staff.name,
      phone: staff.phone || '',
      email: staff.email || '',
      department: staff.department || '',
      title: staff.title || '',
      role: staff.role || 'staff',
      positions: staff.positions || [],
      baseUBI: staff.baseUBI || 0,
      ubiPercentage: staff.ubiPercentage || 100,
      status: staff.status || 'active'
    });
  };

  const handlePositionToggle = (pos) => {
    const currentPositions = editForm.positions || [];
    if (currentPositions.includes(pos)) {
      setEditForm({ ...editForm, positions: currentPositions.filter(p => p !== pos) });
    } else {
      setEditForm({ ...editForm, positions: [...currentPositions, pos] });
    }
  };

  const saveEdit = (id) => {
    updateStaffInfo(id, editForm);
    setEditMode(null);
    alert("Cập nhật thông tin thành công!");
  };

  const systemRoleName = (r) => {
    switch(r) {
        case 'chief': return 'Chief Admin';
        case 'reg': return 'Reg Manager';
        case 'op': return 'Op Manager';
        default: return 'Staff';
    }
  };

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #003366', paddingBottom: '10px', marginTop: 0 }}>Quản lý Nhân sự</h2>

      {/* Form thêm mới (Chief Only) */}
      {isChief && (
        <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', marginBottom: '20px' }}>
          <h4 style={{ margin: '0 0 15px 0', color: '#003366' }}>+ Thêm nhân sự mới</h4>
          <form onSubmit={handleAdd} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
            <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required style={styles.input} />
            <input placeholder="Username" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} required style={styles.input} />
            <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} required style={styles.input} />
            <button type="submit" style={styles.btnAdd}><Icons.Add /> Tạo</button>
          </form>
        </div>
      )}

      {/* Grid Danh Sách */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
        {staffList.map(staff => (
          <div key={staff.id} style={{ 
              background: 'white', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', padding: '15px', 
              border: editMode === staff.id ? '2px solid #003366' : '1px solid #e0e0e0',
              opacity: (staff.status === 'suspended' && editMode !== staff.id) ? 0.6 : 1,
              display: 'flex', flexDirection: 'column'
          }}>
            
            {/* Header Card */}
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px', borderBottom: '1px solid #f0f0f0', paddingBottom: '8px' }}>
               <div>
                  <strong style={{ fontSize: '1.05rem', color: '#333' }}>{staff.name}</strong>
                  <div style={{ fontSize: '0.8rem', color: '#888' }}>@{staff.username}</div>
               </div>
               <span style={{ 
                  background: staff.role === 'chief' ? '#003366' : '#f0f2f5', 
                  color: staff.role === 'chief' ? 'white' : '#555',
                  padding: '2px 8px', borderRadius: '4px', fontSize: '0.7rem', height: 'fit-content', fontWeight: '600'
               }}>
                  {systemRoleName(staff.role)}
               </span>
            </div>

            {/* Body Card */}
            <div style={{ flex: 1 }}>
              {editMode === staff.id ? (
                // --- Edit Form ---
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    <div style={styles.group}>
                        <label style={styles.label}>Thông tin</label>
                        <input value={editForm.name} onChange={e => setEditForm({...editForm, name: e.target.value})} placeholder="Tên" style={styles.inputFull} />
                        <div style={{display:'flex', gap: '5px'}}>
                             <input value={editForm.phone} onChange={e => setEditForm({...editForm, phone: e.target.value})} placeholder="Phone" style={styles.inputFull} />
                             <input value={editForm.email} onChange={e => setEditForm({...editForm, email: e.target.value})} placeholder="Email" style={styles.inputFull} />
                        </div>
                    </div>

                    {(isChief || isOp || isReg) && (
                        <div style={styles.group}>
                            <label style={styles.label}>Vị trí (Functional Roles)</label>
                            <div style={{ display: 'flex', flexWrap: 'wrap', gap: '5px' }}>
                                {(isChief || isOp) && opFunctionalRoles.map(r => (
                                    <label key={r} style={styles.checkboxLabel}><input type="checkbox" checked={editForm.positions?.includes(r)} onChange={() => handlePositionToggle(r)} /> {r}</label>
                                ))}
                                {(isChief || isReg) && regFunctionalRoles.map(r => (
                                    <label key={r} style={styles.checkboxLabel}><input type="checkbox" checked={editForm.positions?.includes(r)} onChange={() => handlePositionToggle(r)} /> {r}</label>
                                ))}
                            </div>
                        </div>
                    )}
                    
                    {isChief && (
                         <div style={styles.group}>
                             <label style={styles.label}>UBI & Trạng thái</label>
                             <div style={{display:'flex', gap: '5px'}}>
                                <input type="number" value={editForm.baseUBI} onChange={e => setEditForm({...editForm, baseUBI: Number(e.target.value)})} placeholder="UBI" style={styles.inputFull} />
                                <select value={editForm.ubiPercentage} onChange={e => setEditForm({...editForm, ubiPercentage: Number(e.target.value)})} style={{width: '70px', ...styles.inputFull}}>
                                    <option value={100}>100%</option><option value={75}>75%</option><option value={50}>50%</option><option value={25}>25%</option>
                                </select>
                             </div>
                             <select value={editForm.status} onChange={e => setEditForm({...editForm, status: e.target.value})} style={{marginTop:'5px', ...styles.inputFull}}>
                                 <option value="active">Active</option><option value="suspended">Suspended</option>
                             </select>
                         </div>
                    )}

                    <div style={{ display: 'flex', gap: '5px', marginTop: '5px' }}>
                        <button onClick={() => saveEdit(staff.id)} style={styles.btnSave}><Icons.Save /> Lưu</button>
                        <button onClick={() => setEditMode(null)} style={styles.btnCancel}>Hủy</button>
                    </div>
                </div>
              ) : (
                // --- View Mode ---
                <div>
                   {(staff.positions && staff.positions.length > 0) ? (
                       <div style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', marginBottom: '8px' }}>
                           {staff.positions.map(p => (
                               <span key={p} style={{ background: '#333', color: 'white', fontSize: '0.65rem', padding: '2px 5px', borderRadius: '3px' }}>{p}</span>
                           ))}
                       </div>
                   ) : <div style={{ fontSize: '0.75rem', color: '#999', fontStyle: 'italic', marginBottom: '8px' }}>-- Chưa xếp vị trí --</div>}

                   <div style={{ fontSize: '0.8rem', color: '#666', lineHeight: '1.4' }}>
                       {staff.phone && <div>📞 {staff.phone}</div>}
                       {staff.email && <div>✉️ {staff.email}</div>}
                       {isChief && (
                           <div style={{ marginTop: '5px', color: '#28a745', fontWeight: 'bold' }}>
                               UBI: {((staff.baseUBI || 0) * (staff.ubiPercentage || 100) / 100).toLocaleString()} <span style={{fontSize:'0.8em', color:'#333'}}>VNĐ</span>
                           </div>
                       )}
                   </div>
                </div>
              )}
            </div>

            {/* Footer Card: Action Buttons (Nằm trong thẻ) */}
            {!editMode && (
                <div style={{ marginTop: '15px', paddingTop: '10px', borderTop: '1px dashed #eee', display: 'flex', justifyContent: 'flex-end', gap: '8px' }}>
                    {canAccessManager && (
                        <button onClick={() => startEdit(staff)} style={styles.btnEdit} title="Chỉnh sửa">
                            <Icons.Edit /> Điều chỉnh
                        </button>
                    )}
                    {isChief && (
                        <button onClick={() => handleDelete(staff.id)} style={styles.btnDelete} title="Xóa">
                            <Icons.Delete /> Xóa
                        </button>
                    )}
                </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
    input: { padding: '8px', border: '1px solid #ddd', borderRadius: '4px', flex: 1 },
    inputFull: { padding: '6px', border: '1px solid #ddd', borderRadius: '4px', width: '100%', boxSizing: 'border-box' },
    group: { background: '#f9f9f9', padding: '8px', borderRadius: '4px', marginBottom: '6px' },
    label: { fontSize: '0.7rem', fontWeight: 'bold', color: '#666', marginBottom: '3px', display: 'block' },
    checkboxLabel: { fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '3px', background: 'white', padding: '2px 5px', border: '1px solid #eee', borderRadius: '3px' },
    btnAdd: { background: '#28a745', color: 'white', border: 'none', borderRadius: '4px', padding: '8px 15px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' },
    btnSave: { background: '#003366', color: 'white', border: 'none', borderRadius: '4px', padding: '6px', flex: 1, cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '5px' },
    btnCancel: { background: '#888', color: 'white', border: 'none', borderRadius: '4px', padding: '6px 12px', cursor: 'pointer' },
    btnEdit: { background: 'white', border: '1px solid #003366', color: '#003366', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.8rem' },
    btnDelete: { background: '#ffebee', border: '1px solid #ffcdd2', color: '#d32f2f', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px', fontSize: '0.8rem' }
};

export default StaffManager;
